import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { 
  BarChart3, 
  TrendingUp, 
  PieChart, 
  Calendar, 
  Filter,
  Download,
  Activity,
  CheckCircle,
  Clock,
  AlertCircle,
  FileText,
  ArrowUp,
  ArrowDown,
  MoreVertical,
  Printer,
  Mail,
  Share2
} from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

const Analytics = () => {
  const { api } = useAuth();
  const [stats, setStats] = useState({
    totalComplaints: 0,
    resolvedComplaints: 0,
    pendingComplaints: 0,
    inProgressComplaints: 0,
    byCategory: {},
    byPriority: {},
    monthlyTrends: []
  });
  const [loading, setLoading] = useState(true);
  const [selectedPeriod, setSelectedPeriod] = useState('30');
  const [complaints, setComplaints] = useState([]);
  const [exporting, setExporting] = useState(false);

  useEffect(() => {
    fetchAnalytics();
    fetchComplaintsForExport();
  }, []);

  const fetchAnalytics = async () => {
    try {
      setLoading(true);
      const response = await api.get('/complaints/stats');
      setStats(response.data);
    } catch (error) {
      console.error('Error fetching analytics:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchComplaintsForExport = async () => {
    try {
      const response = await api.get('/complaints?size=1000&sortBy=createdAt&sortDir=desc');
      setComplaints(response.data.content || response.data || []);
    } catch (error) {
      console.error('Error fetching complaints for export:', error);
    }
  };

  const generatePDFReport = () => {
    setExporting(true);
    try {
      const doc = new jsPDF();

      // Header
      doc.setFontSize(20);
      doc.setTextColor(31, 41, 55);
      doc.text('Complaint Management System Analytics Report', 20, 20);

      doc.setFontSize(12);
      doc.setTextColor(107, 114, 128);
      doc.text(`Generated on: ${new Date().toLocaleDateString()}`, 20, 30);
      doc.text(`Period: Last ${selectedPeriod} days`, 20, 37);

      // Executive Summary
      doc.setFontSize(14);
      doc.setTextColor(31, 41, 55);
      doc.text('Executive Summary', 20, 50);

      // Summary Table
      const summaryData = [
        ['Metric', 'Count', 'Percentage'],
        ['Total Complaints', stats.totalComplaints || 0, '100%'],
        ['Resolved', stats.resolvedComplaints || 0, `${((stats.resolvedComplaints / stats.totalComplaints) * 100 || 0).toFixed(1)}%`],
        ['In Progress', stats.inProgressComplaints || 0, `${((stats.inProgressComplaints / stats.totalComplaints) * 100 || 0).toFixed(1)}%`],
        ['Pending', stats.pendingComplaints || 0, `${((stats.pendingComplaints / stats.totalComplaints) * 100 || 0).toFixed(1)}%`]
      ];

      autoTable(doc, {
        head: [summaryData[0]],
        body: summaryData.slice(1),
        startY: 60,
        theme: 'grid',
        headStyles: { fillColor: [59, 130, 246], textColor: 255 },
        styles: { fontSize: 10 }
      });

      // Category Analysis
      const categoryData = Object.entries(stats.byCategory || {}).map(([category, count]) => [
        category.replace('_', ' '),
        count,
        `${((count / stats.totalComplaints) * 100 || 0).toFixed(1)}%`
      ]);

      if (categoryData.length > 0) {
        doc.setFontSize(14);
        doc.setTextColor(31, 41, 55);
        doc.text('Category Analysis', 20, doc.lastAutoTable.finalY + 15);

        doc.autoTable({
          head: [['Category', 'Count', 'Percentage']],
          body: categoryData,
          startY: doc.lastAutoTable.finalY + 25,
          theme: 'grid',
          headStyles: { fillColor: [16, 185, 129], textColor: 255 },
          styles: { fontSize: 10 }
        });
      }

      // Priority Analysis
      const priorityData = Object.entries(stats.byPriority || {}).map(([priority, count]) => [
        priority,
        count,
        `${((count / stats.totalComplaints) * 100 || 0).toFixed(1)}%`
      ]);

      if (priorityData.length > 0) {
        doc.setFontSize(14);
        doc.setTextColor(31, 41, 55);
        doc.text('Priority Analysis', 20, doc.lastAutoTable.finalY + 15);

        doc.autoTable({
          head: [['Priority', 'Count', 'Percentage']],
          body: priorityData,
          startY: doc.lastAutoTable.finalY + 25,
          theme: 'grid',
          headStyles: { fillColor: [251, 146, 60], textColor: 255 },
          styles: { fontSize: 10 }
        });
      }

      // Detailed Complaints List
      if (complaints.length > 0) {
        doc.addPage();
        doc.setFontSize(14);
        doc.setTextColor(31, 41, 55);
        doc.text('Detailed Complaints List', 20, 20);

        const complaintsData = complaints.slice(0, 50).map(complaint => [
          complaint.id || '',
          complaint.title || '',
          complaint.status || '',
          complaint.priority || '',
          complaint.assetCategory?.replace('_', ' ') || '',
          new Date(complaint.createdAt || '').toLocaleDateString()
        ]);

        doc.autoTable({
          head: [['ID', 'Title', 'Status', 'Priority', 'Category', 'Date']],
          body: complaintsData,
          startY: 30,
          theme: 'grid',
          headStyles: { fillColor: [139, 92, 246], textColor: 255 },
          styles: { fontSize: 8 },
          columnStyles: {
            0: { cellWidth: 10 },
            1: { cellWidth: 40 },
            2: { cellWidth: 20 },
            3: { cellWidth: 20 },
            4: { cellWidth: 30 },
            5: { cellWidth: 25 }
          }
        });
      }

      // Footer
      const pageCount = doc.internal.getNumberOfPages();
      for (let i = 1; i <= pageCount; i++) {
        doc.setPage(i);
        doc.setFontSize(8);
        doc.setTextColor(107, 114, 128);
        doc.text(`Page ${i} of ${pageCount}`, doc.internal.pageSize.width - 30, doc.internal.pageSize.height - 10);
        doc.text('Confidential - Internal Use Only', 20, doc.internal.pageSize.height - 10);
      }

      // Save the PDF
      doc.save(`analytics-report-${new Date().toISOString().split('T')[0]}.pdf`);

    } catch (error) {
      console.error('Error generating PDF:', error);
    } finally {
      setExporting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  const resolutionRate = stats.totalComplaints ? ((stats.resolvedComplaints / stats.totalComplaints) * 100).toFixed(1) : 0;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header Section */}
      <div className="bg-gradient-to-r from-blue-600 to-indigo-700 rounded-2xl p-8 text-white mb-8 relative overflow-hidden shadow-xl">
        <div className="absolute top-0 right-0 -mr-24 -mt-24 h-96 w-96 rounded-full bg-white/10 blur-3xl"></div>
        <div className="absolute bottom-0 left-0 -ml-16 -mb-16 h-64 w-64 rounded-full bg-white/5 blur-2xl"></div>

        <div className="relative z-10">
          <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-6">
            <div>
              <h1 className="text-4xl font-bold mb-3 flex items-center">
                <BarChart3 className="mr-4 h-10 w-10" />
                Analytics Dashboard
              </h1>
              <p className="text-blue-100 text-lg">Comprehensive insights into complaint management performance</p>
            </div>

            <div className="flex flex-col sm:flex-row gap-3">
              <select 
                value={selectedPeriod}
                onChange={(e) => setSelectedPeriod(e.target.value)}
                className="bg-white/20 backdrop-blur border border-white/30 text-white px-4 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-white/50"
              >
                <option value="7">Last 7 Days</option>
                <option value="30">Last 30 Days</option>
                <option value="90">Last 90 Days</option>
                <option value="365">Last Year</option>
              </select>

              <button
                onClick={generatePDFReport}
                disabled={exporting}
                className="bg-white text-blue-600 px-6 py-3 rounded-lg font-semibold hover:bg-blue-50 transition-all shadow-lg flex items-center justify-center space-x-2 disabled:opacity-50"
              >
                {exporting ? (
                  <>
                    <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-blue-600"></div>
                    <span>Generating...</span>
                  </>
                ) : (
                  <>
                    <Download className="h-5 w-5" />
                    <span>Export PDF Report</span>
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Key Performance Indicators */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <KpiCard 
          title="Total Complaints" 
          value={stats.totalComplaints || 0} 
          icon={<Activity className="h-6 w-6" />} 
          color="from-blue-500 to-blue-600"
          trend={+12}
          description="vs last month"
        />
        <KpiCard 
          title="Resolution Rate" 
          value={`${resolutionRate}%`} 
          icon={<CheckCircle className="h-6 w-6" />} 
          color="from-green-500 to-green-600"
          trend={+8}
          description="vs last month"
        />
        <KpiCard 
          title="In Progress" 
          value={stats.inProgressComplaints || 0} 
          icon={<TrendingUp className="h-6 w-6" />} 
          color="from-indigo-500 to-indigo-600"
          trend={-3}
          description="vs last month"
        />
        <KpiCard 
          title="Pending" 
          value={stats.pendingComplaints || 0} 
          icon={<Clock className="h-6 w-6" />} 
          color="from-amber-500 to-amber-600"
          trend={+5}
          description="vs last month"
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
        {/* Category Distribution */}
        <div className="bg-white rounded-2xl shadow-lg p-6 border border-gray-100">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-xl font-bold text-gray-900 flex items-center">
              <PieChart className="mr-3 h-6 w-6 text-blue-600" />
              Category Distribution
            </h2>
            <button className="text-sm font-medium text-blue-600 hover:text-blue-700 flex items-center">
              <MoreVertical className="h-4 w-4 mr-1" />
              Details
            </button>
          </div>

          <div className="space-y-4">
            {Object.entries(stats.byCategory || {}).map(([category, count], index) => {
              const percentage = stats.totalComplaints ? ((count / stats.totalComplaints) * 100).toFixed(1) : 0;
              const colors = ['bg-blue-500', 'bg-green-500', 'bg-indigo-500', 'bg-amber-500', 'bg-purple-500'];
              const color = colors[index % colors.length];

              return (
                <div key={category} className="space-y-2">
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-semibold text-gray-700">
                      {category.replace('_', ' ')}
                    </span>
                    <div className="flex items-center space-x-2">
                      <span className="text-sm font-bold text-gray-900">{count}</span>
                      <span className="text-xs text-gray-500">({percentage}%)</span>
                    </div>
                  </div>
                  <div className="h-3 w-full bg-gray-100 rounded-full overflow-hidden">
                    <div 
                      className={`h-full ${color} rounded-full transition-all duration-500`}
                      style={{ width: `${percentage}%` }}
                    ></div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Priority Analysis */}
        <div className="bg-white rounded-2xl shadow-lg p-6 border border-gray-100">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-xl font-bold text-gray-900 flex items-center">
              <AlertCircle className="mr-3 h-6 w-6 text-amber-600" />
              Priority Analysis
            </h2>
            <div className="flex items-center space-x-2 text-xs bg-gray-50 p-1 rounded-lg">
              <span className="px-3 py-1 bg-white rounded shadow-sm font-bold text-blue-600">Last {selectedPeriod} Days</span>
            </div>
          </div>

          <div className="space-y-4">
            {Object.entries(stats.byPriority || {}).map(([priority, count], index) => {
              const percentage = stats.totalComplaints ? ((count / stats.totalComplaints) * 100).toFixed(1) : 0;
              const priorityColors = {
                'HIGH': 'bg-red-500',
                'MEDIUM': 'bg-amber-500', 
                'LOW': 'bg-green-500',
                'URGENT': 'bg-purple-500'
              };
              const color = priorityColors[priority] || 'bg-gray-500';

              return (
                <div key={priority} className="flex items-center justify-between p-4 bg-gray-50 rounded-xl hover:bg-gray-100 transition-colors">
                  <div className="flex items-center space-x-3">
                    <div className={`w-3 h-3 rounded-full ${color}`}></div>
                    <span className="font-semibold text-gray-700">{priority}</span>
                  </div>
                  <div className="flex items-center space-x-3">
                    <span className="text-2xl font-bold text-gray-900">{count}</span>
                    <span className="text-sm text-gray-500 bg-white px-2 py-1 rounded">{percentage}%</span>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Status Overview */}
      <div className="bg-white rounded-2xl shadow-lg p-6 border border-gray-100">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-gray-900 flex items-center">
            <FileText className="mr-3 h-6 w-6 text-green-600" />
            Status Overview
          </h2>
          <button className="text-sm font-medium text-green-600 hover:text-green-700">View All</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="text-center p-6 bg-green-50 rounded-xl border-2 border-green-200">
            <CheckCircle className="h-12 w-12 text-green-600 mx-auto mb-3" />
            <div className="text-3xl font-bold text-green-900">{stats.resolvedComplaints || 0}</div>
            <div className="text-sm font-medium text-green-700">Resolved</div>
            <div className="text-xs text-green-600 mt-1">{resolutionRate}% completion rate</div>
          </div>

          <div className="text-center p-6 bg-blue-50 rounded-xl border-2 border-blue-200">
            <TrendingUp className="h-12 w-12 text-blue-600 mx-auto mb-3" />
            <div className="text-3xl font-bold text-blue-900">{stats.inProgressComplaints || 0}</div>
            <div className="text-sm font-medium text-blue-700">In Progress</div>
            <div className="text-xs text-blue-600 mt-1">Being actively worked on</div>
          </div>

          <div className="text-center p-6 bg-amber-50 rounded-xl border-2 border-amber-200">
            <Clock className="h-12 w-12 text-amber-600 mx-auto mb-3" />
            <div className="text-3xl font-bold text-amber-900">{stats.pendingComplaints || 0}</div>
            <div className="text-sm font-medium text-amber-700">Pending</div>
            <div className="text-xs text-amber-600 mt-1">Awaiting assignment</div>
          </div>
        </div>
      </div>
    </div>
  );
};

const KpiCard = ({ title, value, icon, color, trend, description }) => {
  const isPositive = trend > 0;

  return (
    <div className="bg-white rounded-2xl p-6 shadow-lg border border-gray-100 hover:shadow-xl transition-shadow">
      <div className="flex items-center justify-between mb-4">
        <div className={`p-3 rounded-xl bg-gradient-to-r ${color} text-white`}>
          {icon}
        </div>
        <div className={`flex items-center space-x-1 text-sm font-bold px-2 py-1 rounded-full ${
          isPositive ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
        }`}>
          {isPositive ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />}
          <span>{Math.abs(trend)}%</span>
        </div>
      </div>

      <div>
        <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-1">{title}</h3>
        <div className="flex items-baseline space-x-2">
          <span className="text-3xl font-black text-gray-900">{value}</span>
        </div>
        <p className="text-xs text-gray-500 mt-1">{description}</p>
      </div>
    </div>
  );
};

export default Analytics;
